"""Run from your insightforge project root:  python3 install_stage4.py"""
import base64
from pathlib import Path
ROOT = Path(__file__).parent
FILES = {
  "backend/app/security/sql_firewall.py": "",
  "backend/app/security/audit_log.py": "",
  "backend/app/db/executor.py": "",
  "backend/app/agents/investigation_planner.py": "",
  "backend/app/agents/sql_generator.py": "",
  "backend/app/agents/query_repair.py": "",
  "backend/tests/test_sql_firewall.py": "",
  "backend/tests/test_investigation_planner.py": ""
}
for rel, b64 in FILES.items():
    p = ROOT / rel
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_bytes(base64.b64decode(b64))
    print(f"  wrote {rel}")
print("\nDone! Now run: make test")
